#include <stdio.h>
#define MOD 1000000007
int dp[500005];
int main() {
    int n;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    dp[0] = 1;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            int min = a[i - j];
            int max = a[i - j];
            for (int k = i - j + 1; k <= i; k++) {
                min = (min < a[k - 1]) ? min : a[k - 1];
                max = (max > a[k - 1]) ? max : a[k - 1];
            }
            if (j >= min && j <= max) {
                dp[i] = (dp[i] + dp[i - j]) % MOD;
            }
        }
    }
    printf("%d\n", dp[n]);
    return 0;
}

