                min = Math.min(min, a[k - 1]);
                max = Math.max(max, a[k - 1]);
            }
            if (j >= min && j <= max) {
                dp[i] = (dp[i] + dp[i - j]) % MOD;
            }
        }
    }
    return dp[n];
}
